package com.chaobo.scm.supplier.interfaces.web;import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.rfq.*;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.web.bind.annotation.*;import java.time.*;import java.util.*;
@RestController @RequestMapping("/openapi/supplier/v1/rfqs") public class RfqOpenApiController{private final RfqEventConsumerApplicationService service;public RfqOpenApiController(RfqEventConsumerApplicationService service){this.service=service;}@PostMapping public ApiResponse<Void> receive(@Valid @RequestBody Request body,HttpServletRequest request,Authentication auth){if(!"PURCHASE".equals(request.getHeader("X-Source-System")))throw new com.chaobo.scm.common.error.BusinessException(com.chaobo.scm.common.error.ErrorCode.FORBIDDEN,"来源系统必须是PURCHASE");for(long supplierId:body.supplierIds())service.consume(new RfqEvent(request.getHeader("X-Event-Code"),body.eventType(),"PURCHASE",body.rfqId(),body.rfqNo(),supplierId,body.quoteDeadline(),body.payload()));return ApiResponse.success(null,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}public record Request(@NotBlank String eventType,@Positive long rfqId,@NotBlank String rfqNo,@NotEmpty List<@Positive Long> supplierIds,OffsetDateTime quoteDeadline,Map<String,Object> payload){}}
